/*
 * sqrt() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly sqrt  (test_sqrt_opt.elf)
 *   2. Linked with toolchain's default sqrt       (test_sqrt_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += sqrt(vx);
#else
    double r = sqrt(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

#ifndef EN_PERF
/* ------------------------------------------------------------------ */
/* Dense sweeps (accuracy path only)                                  */
/* ------------------------------------------------------------------ */

/* Sweep [0, 100] in 200 steps */
static void test_sweep(void)
{
    double hi = 100.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    /* [0, 100] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* Negative values (domain error) */
    for (int i = 1; i <= 20; i++)
        emit(-((double)i * step));
}

/* Sample [0, 10] at key bit patterns */
static void test_exhaustive_small(void)
{
    static const uint64_t vals[] = {
        0x0000000000000000ULL, /* 0.0 */
        0x3fd0000000000000ULL, /* 0.25 */
        0x3fe0000000000000ULL, /* 0.5 */
        0x3ff0000000000000ULL, /* 1.0 */
        0x4000000000000000ULL, /* 2.0 */
        0x4010000000000000ULL, /* 4.0 */
        0x4022000000000000ULL, /* 9.0 */
        0x4024000000000000ULL, /* 10.0 */
    };
    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
        emit_u(vals[i]);
}
#endif /* !EN_PERF */

/* ------------------------------------------------------------------ */
/* Representative 100-point test                                      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (9) --- */
    emit(0.0);                                        /* +0 -> +0 */
    emit(-0.0);                                       /* -0 -> -0 (special case) */
    emit_u(0x7ff8000000000000ULL);                    /* qNaN -> qNaN */
    emit_u(0x7ff0000000000001ULL);                    /* sNaN -> NaN */
    emit_u(0xfff8000000000000ULL);                    /* -qNaN -> NaN */
    emit_u(0x7ff0000000000000ULL);                    /* +Inf -> +Inf */
    emit_u(0xfff0000000000000ULL);                    /* -Inf -> NaN (domain error) */
    emit(-1.0);                                       /* negative normal -> NaN */
    emit(-4.0);                                       /* negative perfect square -> NaN */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);                    /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);                    /* min negative subnormal -> NaN */
    emit_u(0x0008000000000000ULL);                    /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);                    /* mid negative subnormal -> NaN */
    emit_u(0x000fffffffffffffULL);                    /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);                    /* max negative subnormal -> NaN */

    /* --- Section 3: Normal boundary values (6) --- */
    emit(DBL_MIN);                                    /* smallest normal: 2^-1022 */
    emit(-DBL_MIN);                                   /* negative smallest normal -> NaN */
    emit_u(0x0010000000000001ULL);                    /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);                    /* DBL_MAX */
    emit_u(0xffefffffffffffffULL);                    /* -DBL_MAX -> NaN */
    emit_u(0x7feffffffffffff0ULL);                    /* a few ULPs below DBL_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);                    /* one ULP below 1.0 */
    emit(1.0);                                        /* sqrt(1) = 1 exactly */
    emit_u(0x3ff0000000000001ULL);                    /* one ULP above 1.0 */
    emit_u(0x3feffffffffffff0ULL);                    /* a few ULPs below 1.0 */
    emit_u(0x3ff0000000000010ULL);                    /* a few ULPs above 1.0 */
    emit_u(0x3ff0000000000002ULL);                    /* two ULPs above 1.0 */
    emit_u(0x3feffffffffffffeULL);                    /* two ULPs below 1.0 */
    emit_u(0x3ff0000000000100ULL);                    /* many ULPs above 1.0 */

    /* --- Section 5: Exponent switching points (8) --- */
    emit_u(0x3fe0000000000000ULL);                    /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);                    /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);                    /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);                    /* 2.0 */
    emit_u(0x3fffffffffffffffULL);                    /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);                    /* one ULP above 2.0 */
    emit_u(0x4010000000000000ULL);                    /* 4.0 */
    emit_u(0x4020000000000000ULL);                    /* 8.0 */

    /* --- Section 6: Perfect squares and known mathematical values (14) --- */
    emit(4.0);                                        /* sqrt(4) = 2 exactly */
    emit(9.0);                                        /* sqrt(9) = 3 exactly */
    emit(16.0);                                       /* sqrt(16) = 4 exactly */
    emit(25.0);                                       /* sqrt(25) = 5 exactly */
    emit(36.0);                                       /* sqrt(36) = 6 exactly */
    emit(49.0);                                       /* sqrt(49) = 7 exactly */
    emit(100.0);                                      /* sqrt(100) = 10 exactly */
    emit(144.0);                                      /* sqrt(144) = 12 exactly */
    emit(169.0);                                      /* sqrt(169) = 13 exactly */
    emit(2.0);                                        /* sqrt(2): irrational */
    emit(3.0);                                        /* sqrt(3): irrational */
    emit(0.5);                                        /* sqrt(0.5) = 1/sqrt(2) */
    emit(0.25);                                       /* sqrt(0.25) = 0.5 exactly */
    emit(0.0625);                                     /* sqrt(0.0625) = 0.25 exactly */

    /* --- Section 7: ULP neighbors of perfect squares (15) --- */
    emit_u(0x3fefffffffffffffULL);                    /* one ULP below 1.0 */
    emit_u(0x3ff0000000000001ULL);                    /* one ULP above 1.0 */
    emit_u(0x400fffffffffffffULL);                    /* one ULP below 4.0 */
    emit_u(0x4010000000000001ULL);                    /* one ULP above 4.0 */
    emit_u(0x4021ffffffffffffULL);                    /* one ULP below 9.0 */
    emit_u(0x4022000000000001ULL);                    /* one ULP above 9.0 */
    emit_u(0x402fffffffffffffULL);                    /* one ULP below 16.0 */
    emit_u(0x4030000000000001ULL);                    /* one ULP above 16.0 */
    emit_u(0x4038ffffffffffffULL);                    /* one ULP below 25.0 */
    emit_u(0x4039000000000001ULL);                    /* one ULP above 25.0 */
    emit_u(0x3fdffffffffffffeULL);                    /* two ULPs below 0.5: 0.4999... */
    emit_u(0x3fdfffffffffffffULL);                    /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);                    /* one ULP above 0.5 */
    emit_u(0x3fc0000000000000ULL);                    /* 0.125 = 2^-3 */
    emit_u(0x3fe0000000000000ULL);                    /* 0.5 = 2^-1 (repeated for neighbor context) */

    /* --- Section 8: Large values and exponent boundary stress (20) --- */
    emit(1.0e10);                                     /* large positive: 10^10 */
    emit(1.0e20);                                     /* large positive: 10^20 */
    emit(1.0e100);                                    /* very large: 10^100 */
    emit(1.0e200);                                    /* near overflow boundary: 10^200 */
    emit(1.0e300);                                    /* close to DBL_MAX: 10^300 */
    emit(-1.0e10);                                    /* large negative -> NaN */
    emit(-1.0e100);                                   /* very large negative -> NaN */
    emit(1000.0);                                     /* sqrt(1000): irrational */
    emit(10000.0);                                    /* sqrt(10000) = 100 exactly */
    emit(1000000.0);                                  /* sqrt(1e6) = 1000 exactly */
    emit_u(0x4340000000000000ULL);                    /* 2^53: mantissa precision boundary */
    emit_u(0x4350000000000000ULL);                    /* 2^54 */
    emit_u(0x43e0000000000000ULL);                    /* 2^63 */
    emit_u(0x4400000000000000ULL);                    /* 2^64 */
    emit_u(0x47e0000000000000ULL);                    /* 2^127: mid-range large exponent */
    emit_u(0x4fe0000000000000ULL);                    /* 2^255 */
    emit_u(0x5fe0000000000000ULL);                    /* 2^511 */
    emit_u(0x6fe0000000000000ULL);                    /* 2^767 */
    emit_u(0x7fd0000000000000ULL);                    /* near DBL_MAX: 2^1022 */
    emit_u(0x7fe0000000000000ULL);                    /* 2^1023: one exponent below overflow */

    /* --- Section 9: Small positive values near zero (8) --- */
    emit(1.0e-150);                                   /* very small positive */
    emit(1.0e-300);                                   /* near subnormal boundary */
    emit(1.0e-307);                                   /* just above subnormal region */
    emit(1.0e-308);                                   /* at subnormal boundary */
    emit_u(0x0010000000000000ULL);                    /* DBL_MIN = 2^-1022 */
    emit_u(0x0020000000000000ULL);                    /* 2 * DBL_MIN = 2^-1021 */
    emit_u(0x0040000000000000ULL);                    /* 4 * DBL_MIN = 2^-1020 */
    emit_u(0x0080000000000000ULL);                    /* 8 * DBL_MIN = 2^-1019 */

    /* --- Section 10: Rational and irrational inputs at varied scales (6) --- */
    emit(0.1);                                        /* non-dyadic fraction */
    emit(0.3);                                        /* non-dyadic fraction */
    emit(1.5);                                        /* between 1 and 2 */
    emit(2.5);                                        /* between 2 and 4 (irrational result) */
    emit(6.25);                                       /* sqrt(6.25) = 2.5 exactly */
    emit(7.0);                                        /* sqrt(7): irrational */
}

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf g_acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}
